```bash
cd /llvm-autofix-deps/llvm/llvm && sed -i '1041a\    // For single-source shuffles, ensure NumSrcElts is at least as large as the maximum index.
    int MaxIndex = -1;
    for (int M : Mask) {
      if (M != -1 && M > MaxIndex)
        MaxIndex = M;
    }
    if (Kind == TTI::SK_PermuteSingleSrc && MaxIndex >= NumSrcElts) {
      // The mask indices refer to a source larger than the destination.
      // Adjust NumSrcElts to avoid out-of-bounds assertions.
      NumSrcElts = MaxIndex + 1;
    }' llvm/include/llvm/CodeGen/BasicTTIImpl.h
```

